section.script:
(function () {
    const documentTypeEl = document.getElementById('x_id_document_type');
    const documentNumberEl = document.getElementById('x_id_number');
    const documentHintEl = document.getElementById('x_id_number_hint');

    function updateDocumentValidationByType() {
        if (!documentTypeEl || !documentNumberEl) {
            return;
        }

        const isPassport = documentTypeEl.value === 'passport';
        if (isPassport) {
            documentNumberEl.setAttribute('pattern', '[A-Za-z0-9]{6,12}');
            documentNumberEl.setAttribute('minlength', '6');
            documentNumberEl.setAttribute('maxlength', '12');
            documentNumberEl.removeAttribute('inputmode');
            documentNumberEl.setAttribute('title', 'Hộ chiếu chỉ gồm chữ và số, độ dài từ 6 đến 12 ký tự');
            if (documentHintEl) {
                documentHintEl.textContent = 'Nếu chọn Hộ chiếu, vui lòng nhập chữ và số, độ dài từ 6 đến 12 ký tự.';
            }
        } else {
            documentNumberEl.setAttribute('pattern', '[0-9]{12}');
            documentNumberEl.setAttribute('minlength', '12');
            documentNumberEl.setAttribute('maxlength', '12');
            documentNumberEl.setAttribute('inputmode', 'numeric');
            documentNumberEl.setAttribute('title', 'CCCD phải gồm đúng 12 chữ số');
            if (documentHintEl) {
                documentHintEl.textContent = 'Nếu chọn CCCD, vui lòng nhập đúng 12 chữ số.';
            }
        }
    }

    if (documentTypeEl && documentNumberEl) {
        updateDocumentValidationByType();
        documentTypeEl.addEventListener('change', updateDocumentValidationByType);
    }
})();
